import{_ as a,o as i,c as r,a3 as n}from"./chunks/framework.oxq6d-og.js";const p=JSON.parse('{"title":"Hook yaşam döngüsü","description":"","frontmatter":{},"headers":[],"relativePath":"hooking/lifecycle.md","filePath":"hooking/lifecycle.md"}'),o={name:"hooking/lifecycle.md"};function l(d,e,t,s,c,k){return i(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="hook-yasam-dongusu" tabindex="-1">Hook yaşam döngüsü <a class="header-anchor" href="#hook-yasam-dongusu" aria-label="Permalink to &quot;Hook yaşam döngüsü&quot;">​</a></h1><p>NHook ve MinHook&#39;ta <code>create</code>, <code>enable</code>, <code>disable</code> ve <code>destroy</code> ayrı adımlardır. Ortak isimlere rağmen cleanup ve hit işleme davranışları aynı değildir; hook türünü bilmeden genel bir “disable et ve kapat” kuralı yeterli değildir.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>create → hedef/prologue&#39;u doğrula → enable → işle → disable → destroy</span></span></code></pre></div><h2 id="create-ve-enable" tabindex="-1">Create ve enable <a class="header-anchor" href="#create-ve-enable" aria-label="Permalink to &quot;Create ve enable&quot;">​</a></h2><p><code>NHook.create()</code> hedefin başından en az iki byte kaplayacak tam talimatları çözer ve özgün byte&#39;ları saklar. <code>MinHook.create()</code> yeterli prologue&#39;u taşıyan bir trampoline üretir; bu aşama hedefi patch&#39;lemez. Her iki yol için hedef adresinin doğru process&#39;te, executable bellekte ve çözümlenebilir bir fonksiyon başlangıcında olması gerekir.</p><p>Enable sırasında patch yazabilmek için koruma geçici olarak <code>EXECUTE_READWRITE</code> yapılır ve önceki koruma geri yüklenir. Uzak hedefte NHook, patch sırasında erişebildiği diğer thread&#39;leri askıya alır; NThread tabanlı accessor&#39;ın driving thread&#39;i bu işlemden özellikle hariç tutulur. Bu, ayrı suspend sayaçlarının NThread resume akışıyla çakışmasını önler.</p><h2 id="nhook-hit-i-kapatmak-degildir" tabindex="-1">NHook hit&#39;i kapatmak değildir <a class="header-anchor" href="#nhook-hit-i-kapatmak-degildir" aria-label="Permalink to &quot;NHook hit&#39;i kapatmak değildir&quot;">​</a></h2><p>NHook&#39;ta <code>poll()</code> hook&#39;a gelmiş bir thread&#39;i yakalar. <code>resume(hit)</code> ya dönüş değerini zorlar ya da taşınan talimatların desteklenen kısmını simüle edip yürütmeyi sürdürür. Bu işlem context&#39;i uygular, fakat park edilmiş thread&#39;i kendi başına serbest bırakmaz; NHook&#39;un mevcut akışında tam accessor&#39;ın <code>deinit()</code> edilmesi thread&#39;i bırakma ve kaynak temizliğinin parçasıdır.</p><p>Bu nedenle NHook hit&#39;i ile çalışırken accessor sahipliğini ve <code>deinit()</code> zamanını açıkça tasarlayın. Birden çok hit, uzun süren kullanıcı kodu veya desteklenmeyen prologue talimatları için lifecycle&#39;ı küçük, kontrollü bir hedefte doğrulayın.</p><h2 id="disable-ve-destroy" tabindex="-1">Disable ve destroy <a class="header-anchor" href="#disable-ve-destroy" aria-label="Permalink to &quot;Disable ve destroy&quot;">​</a></h2><p><code>disable()</code> hedefin özgün byte&#39;larını geri yazar; <code>destroy()</code> etkin hook&#39;u önce disable eder, sonra hook kaydını ve MinHook&#39;ta trampoline/relay kaynaklarını kaldırır. Disable sonrasında hedefin yeni çağrılarının özgün koda gittiğini doğrulayın. Hedef process kapanırken ya da timeout sonrası context belirsizken cleanup&#39;ın kusursuz geri dönüş sağlayacağını varsaymayın.</p><p>Kapanış yolunu normal akış kadar test edin: <code>try/finally</code> kullanın, aynı adrese ikinci hook kurmayın ve hata anında hangi accessor&#39;ın hangi thread&#39;i sürdüğünü loglayın.</p>',12)])])}const u=a(o,[["render",l]]);export{p as __pageData,u as default};
